// INPUT: an array of OCR results, one per file, like your sample
// OUTPUT: one combined object per statement with full text ready for classification

const output = [];

for (const item of items) {
  const pages = item.json.pages || [];
  const combinedText = pages.map(p => p.markdown || p.text || "").join("\n\n");

  output.push({
    json: {
      statement_id: item.json.fileName || `statement_${Math.random().toString(36).slice(2)}`,
      page_count: pages.length,
      fullText: combinedText,
      account_type: item.json.accountType || "checking", // you can set dynamically later
      currency: "CAD"
    }
  });
}

return output;

// INPUT: 19 items, each like { statement_id, fullText, account_type, currency }
// OUTPUT: 1 item with mergedStatements array

return [{
  json: {
    mergedStatements: items.map(i => ({
      statement_id: i.json.statement_id,
      account_type: i.json.account_type,
      currency: i.json.currency,
      text: i.json.fullText
    }))
  }
}];
